create table users
(
    Id                  uniqueidentifier                                not null
        constraint PK_users
            primary key,
Username nvarchar(50) collate Latin1_General_CS_AS not null,
Password            nvarchar(255)                                   not null,
    first_name          nvarchar(50),
    last_name           nvarchar(50),
    verification_code   nvarchar(6),
    role_id             int       default 0                             not null
        constraint FK_users_roles_role_id
            references roles
            on delete cascade,
    is_active           bit       default CONVERT([bit], 0)             not null,
    created_at          datetime2 default '0001-01-01T00:00:00.0000000' not null,
    deleted_at          datetime2,
    reset_password_code nvarchar(6),
    modified_at         datetime2,
    is_banned           bit       default CONVERT([bit], 0)             not null
)
go

create index IX_users_role_id
    on users (role_id)
go

